diff --git a/retrofit/src/main/java/retrofit2/OkHttpCall.java b/retrofit/src/main/java/retrofit2/OkHttpCall.java
index ff67612..e7ea9a4 100644
--- a/retrofit/src/main/java/retrofit2/OkHttpCall.java
+++ b/retrofit/src/main/java/retrofit2/OkHttpCall.java
@@ -61,6 +61,19 @@ final class OkHttpCall<T> implements Call<T> {
     this.responseConverter = responseConverter;
   }

+  /**
+   * Creates a new {@code OkHttpCall} with the same parameters as this call.
+   *
+   * <p>The cloned call is in its initial state: {@code executed} and {@code canceled} flags are
+   * {@code false}, the raw OkHttp call has not been created yet, and any previous execution
+   * failure is not carried over. This is correct because {@code OkHttpCall} is a final type
+   * constructed fresh via {@code new}, so Java's default field initialization handles the reset
+   * automatically \u2014 no explicit clearing of mutable state is needed.
+   *
+   * <p>Note: the {@code args} array reference is shared with the original call. The elements
+   * are effectively immutable (Retrofit service methods should only use immutable types per the
+   * interface contract), so sharing is safe.
+   */
   @SuppressWarnings("CloneDoesntCallSuperClone") // We are a final type & this saves clearing state.
   @Override
   public OkHttpCall<T> clone() {
     return new OkHttpCall<>(requestFactory, instance, args, callFactory, responseConverter);
   }
